definition.script:
pipeline {
    agent {
        label "windows_x86_64"
    }
    environment {
        ARTIFACTORY_CREDS = credentials('openjdk-artifactory')
    }
    stages {
        stage("Init") {
            steps {

                // trigger workspace cleanup
                cleanWs()

                // check/configure some job parameters
                script {
                    if (params.SAPMACHINE_VERSION.isEmpty()) {
                        env.SAPMACHINE_VERSION = params.GIT_REF
                    } else {
                        env.SAPMACHINE_VERSION = params.SAPMACHINE_VERSION
                    }

                    // initialize some variables
                    env.BUILD_INSTALLER_PACKAGES = params.BUILD_INSTALLER_PACKAGES
                    env.ART_VERSION = "snapshot-22-" + (new java.text.SimpleDateFormat("yyyyMMddHHmmss")).format(new Date())
                    env.RELEASE = "false"
                }
            }
        }
        stage("Checkout Infrastructure Repository") {
            steps {
                sh '''#!/bin/bash
                    set -e

                    if [[ `uname` == CYGWIN* ]]; then
                      GIT_TOOL="/cygdrive/c/Program Files/Git/cmd/git.exe"
                    else
                      GIT_TOOL=git
                    fi

                    "$GIT_TOOL" --version
                    "$GIT_TOOL" config --global init.defaultBranch master
                    (set -ex && "$GIT_TOOL" init SapMachine-infrastructure)
                    cd SapMachine-infrastructure
                    (set -ex && GIT_TERMINAL_PROMPT=0 "$GIT_TOOL" fetch --depth 1 https://github.com/SAP/SapMachine-infrastructure master)
                    (set -ex && "$GIT_TOOL" checkout --detach FETCH_HEAD)
                '''
            }
        }




        stage("Checkout SapMachine Repository") {

            steps {
                sh("SapMachine-infrastructure/lib/git_clone.sh $SAPMACHINE_GIT_REPOSITORY SapMachine $GIT_REF ")
            }
        }
        stage("Prepare Devkit") {

            when {
                beforeAgent true
                expression {  !params.DEVKIT.isEmpty() }
            }
            steps {
                script {
                    String[] gav = params.DEVKIT.split(":");
                    if (gav.length == 3) {
                        echo "Extracting devkit from GAV coordinates: \"${params.DEVKIT}\"."
                        sh("SapMachine-infrastructure/lib/deploy-devkit.sh ${gav[0]} ${gav[1]} ${gav[2]}")
                        env.DEVKIT_PATH = sh(script: "cat devkitlocation.txt", returnStdout: true).trim()
                    } else {
                        echo "Devkit not in GAV notation, assuming path."
                        env.DEVKIT_PATH = params.DEVKIT;
                    }
                    echo "Devkit Path: ${env.DEVKIT_PATH}"
                }
            }
        }
        stage("Download Prerequisites") {


            steps {
                // Download Boot JDK, Credentials are needed to avoid rate limit exceedance
                withCredentials([[$class: 'UsernamePasswordMultiBinding', credentialsId: 'SapMachine-github', usernameVariable: 'GIT_USER', passwordVariable: 'GIT_PASSWORD']]) {
                    sh 'python3 SapMachine-infrastructure/lib/download_boot_jdk.py -d `pwd`'
                }

                // Download googletest
                sh("SapMachine-infrastructure/lib/git_clone.sh https://github.com/google/googletest gtest v1.14.0")

                // Download jtreg if required
                script {
                    if (params.RUN_TESTS) {
                        sh 'python3 SapMachine-infrastructure/lib/download_jtreg.py'
                    }
                }
            }
        }
        stage("Build") {


            environment {
                BOOT_JDK = "${WORKSPACE}/boot_jdk"
            }
            steps {
                withCredentials([[$class: 'UsernamePasswordMultiBinding', credentialsId: 'SapMachine-github', usernameVariable: 'GIT_USER', passwordVariable: 'GIT_PASSWORD'],
                                 string(credentialsId: 'MacOSKeyChainUnlockPW', variable: 'unlockpass')]) {
                    script {
                        sh("SapMachine-infrastructure/lib/build.sh")
                    }
                }
            }
        }
        stage("Zip Artifacts") {


                steps {
                    script {
                        sh("SapMachine-infrastructure/lib/zip_artifacts.sh")

                    }
                }
            }

        stage("Run jtreg hotspot") {

            when {
                beforeAgent true
                expression {  params.RUN_TESTS == true && params.hotspot_test_groups }
            }
            environment {
                TESTSUITE = 'hotspot'
            }
            steps {
                sh 'bash SapMachine-infrastructure/lib/run_jtreg.sh -l `pwd`/SapMachine -h `pwd`/jtreg/jtreg -s $TESTSUITE "$hotspot_test_groups" || true'
                publishHTML target: [
                    allowMissing: false,
                    alwaysLinkToLastBuild: false,
                    keepAll: true,
                    reportDir: "test_report_${env.TESTSUITE}",
                    reportFiles: 'JTreport/index.html',
                    reportName: "JT Report ${env.TESTSUITE}"
                ]
                // persist data for test trend graph
                junit "test_report_${env.TESTSUITE}/JTwork/**/*.jtr.xml"
                script {
                    if (findFiles([glob: 'test_report_${env.TESTSUITE}/JTwork/**/hs_err_pid*.log']).size() > 0) {
                        archiveArtifacts allowEmptyArchive: true, artifacts: "test_report_${env.TESTSUITE}/JTwork/**/hs_err_pid*.log"
                    }
                }
            }
        }
        stage("Run jtreg jdk") {

            when {
                beforeAgent true
                expression {  params.RUN_TESTS == true && params.jdk_test_groups }
            }
            environment {
                TESTSUITE = 'jdk'
            }
            steps {
                sh 'bash SapMachine-infrastructure/lib/run_jtreg.sh -l `pwd`/SapMachine -h `pwd`/jtreg/jtreg -s $TESTSUITE "$jdk_test_groups" || true'

                publishHTML target: [
                    allowMissing: false,
                    alwaysLinkToLastBuild: false,
                    keepAll: true,
                    reportDir: "test_report_${env.TESTSUITE}",
                    reportFiles: 'JTreport/index.html',
                    reportName: "JT Report ${env.TESTSUITE}"
                ]
                // persist data for test trend graph
                junit "test_report_${env.TESTSUITE}/JTwork/**/*.jtr.xml"
                script {
                    if (findFiles([glob: 'test_report_${env.TESTSUITE}/JTwork/**/hs_err_pid*.log']).size() > 0) {
                        archiveArtifacts allowEmptyArchive: true, artifacts: "test_report_${env.TESTSUITE}/JTwork/**/hs_err_pid*.log"
                    }
                }
            }
        }
        stage("Run jtreg langtools") {

            when {
                beforeAgent true
                expression {  params.RUN_TESTS == true && params.langtools_test_groups }
            }
            environment {
                TESTSUITE = 'langtools'
            }
            steps {
                sh 'bash SapMachine-infrastructure/lib/run_jtreg.sh -l `pwd`/SapMachine -h `pwd`/jtreg/jtreg -s $TESTSUITE "$langtools_test_groups" || true'

                publishHTML target: [
                    allowMissing: false,
                    alwaysLinkToLastBuild: false,
                    keepAll: true,
                    reportDir: "test_report_${env.TESTSUITE}",
                    reportFiles: 'JTreport/index.html',
                    reportName: "JT Report ${env.TESTSUITE}"
                ]
                // persist data for test trend graph
                junit "test_report_${env.TESTSUITE}/JTwork/**/*.jtr.xml"
                script {
                    if (findFiles([glob: 'test_report_${env.TESTSUITE}/JTwork/**/hs_err_pid*.log']).size() > 0) {
                        archiveArtifacts allowEmptyArchive: true, artifacts: "test_report_${env.TESTSUITE}/JTwork/**/hs_err_pid*.log"
                    }
                }
            }
        }
        stage("Build Windows Installer") {
            when {
                expression { env.BUILD_INSTALLER_PACKAGES == "true" }
            }
            steps {
                withCredentials([[$class: 'UsernamePasswordMultiBinding', credentialsId: 'SapMachine-github', usernameVariable: 'GIT_USER', passwordVariable: 'GIT_PASSWORD']]) {
                    script {
                        def jdk_bundle_name = readFile "${env.WORKSPACE}/jdk_bundle_name.txt"
                        def jre_bundle_name = readFile "${env.WORKSPACE}/jre_bundle_name.txt"
                        jdk_bundle_name = jdk_bundle_name.trim()
                        jre_bundle_name = jre_bundle_name.trim()

                        sh "python3 SapMachine-infrastructure/lib/packagebuild/make_msi.py --sapmachine-directory=`pwd`/SapMachine --asset=${jdk_bundle_name}"
                        sh "python3 SapMachine-infrastructure/lib/packagebuild/make_msi.py --sapmachine-directory=`pwd`/SapMachine --jre --asset=${jre_bundle_name}"
                    }
                }
            }
        }




        stage("Publish Artifactory") {
            when {
                expression { params.UPLOAD_ARTIFACTORY == true }
            }
            steps {
                // Upload the test and jdk archive
                sh 'curl -sSf -u $ARTIFACTORY_CREDS -X PUT -T test.zip https://common.repositories.cloud.sap/artifactory/sapmachine-mvn/io/sapmachine/build-results/windows_x86_64/${ART_VERSION}/test.zip'
                sh 'curl -sSf -u $ARTIFACTORY_CREDS -X PUT -T jdk.zip https://common.repositories.cloud.sap/artifactory/sapmachine-mvn/io/sapmachine/build-results/windows_x86_64/${ART_VERSION}/jdk.zip'

            }
        }









    }
    post {
        success {
            script {
                // create a gensrc archive
                if (params.CREATE_GENSRC_BUNDLE == true) {
                    sh 'cd SapMachine/build && cd $(ls) && zip -rq ${WORKSPACE}/support_gensrc.zip support/gensrc'
                    archiveArtifacts artifacts: 'support_gensrc.zip'
                }

                // archive workspace on request
                if (params.ARCHIVE_WORKSPACE == true) {
                    sh 'zip -rq workspace.zip .'
                    archiveArtifacts allowEmptyArchive: true, artifacts: 'workspace.zip'
                }
            }
            cleanWs()
        }
        unsuccessful {
            script {
                sh 'zip -rq workspace.zip .'
                archiveArtifacts allowEmptyArchive: true, artifacts: 'workspace.zip'
            }
        }
    }
}
